1	#!/usr/bin/env node
2	'use strict';
3	// verify.js - reference-set harness: match-or-abstain-never-contradict.
4	//
5	// Given an engine output payload, checks it against eval/reference-set/reference-set.json:
6	//   MATCH        engine asserts a value and it agrees with the verified expectation  -> pass
7	//   ABSTAIN      engine omits or marks needs-review a value the set expects          -> allowed, logged
8	//   CONTRADICT   engine asserts a value that disagrees with a verified expectation,
9	//                asserts a jurisdiction outside the verified bound list, or asserts
10	//                any known_non_breach as a breach                                    -> FAIL (exit 1)
11	//
12	// Usage:
13	//   node eval/reference-set/verify.js <payload.json> [--set <reference-set.json>] [--domain <domain>] [--json]
14	//
15	// Exit codes: 0 = no contradictions (abstentions allowed), 1 = at least one contradiction,
16	//             2 = usage or data error (unreadable payload, domain not in the set, ...).
17	//
18	// Payload shape: the v1 contract (payload/schema/payload.schema.json) plus tolerant fallbacks
19	// for the legacy window.D shape, so the harness works before and after the P4 seam lands.
20	// Findings in a non-assertive state (pass / needs-review / unverified / info) never contradict:
21	// only ASSERTED breaches can contradict a known_non_breach. That is the three-state doctrine.
22	
23	const fs = require('fs');
24	const path = require('path');
25	
26	const DEFAULT_SET = path.join(__dirname, 'reference-set.json');
27	
28	// ---------- helpers ----------
29	
30	function norm(s) {
31	  return String(s == null ? '' : s).toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim();
32	}
33	
34	function looseMatch(a, b) {
35	  const na = norm(a);
36	  const nb = norm(b);
37	  if (!na || !nb) return false;
38	  return na === nb || na.includes(nb) || nb.includes(na);
39	}
40	
41	const COUNTRY_TO_CODE = {
42	  'united kingdom': 'UK', 'uk': 'UK', 'gb': 'UK', 'great britain': 'UK', 'england': 'UK',
43	  'scotland': 'UK', 'wales': 'UK', 'northern ireland': 'UK',
44	  'united states': 'US', 'united states of america': 'US', 'usa': 'US', 'us': 'US',
45	  'united arab emirates': 'AE', 'uae': 'AE', 'ae': 'AE',
46	  'ireland': 'IE', 'ie': 'IE', 'republic of ireland': 'IE',
47	  'european union': 'EU', 'eu': 'EU',
48	};
49	
50	function toJurisdictionCode(v) {
51	  const n = norm(v);
52	  return COUNTRY_TO_CODE[n] || (n ? String(v).toUpperCase().trim() : null);
53	}
54	
55	function firstNonNull() {
56	  for (let i = 0; i < arguments.length; i++) {
57	    const v = arguments[i];
58	    if (v !== undefined && v !== null && v !== '') return v;
59	  }
60	  return null;
61	}
62	
63	// ---------- tolerant payload extractors ----------
64	
65	function extractDomain(payload) {
66	  return firstNonNull(
67	    payload && payload.meta && payload.meta.domain,
68	    payload && payload.domain
69	  );
70	}
71	
72	function extractIdentity(payload) {
73	  const id = (payload && (payload.identity || payload.firm_profile || payload.firmProfile)) || {};
74	  return {
75	    legal_name: firstNonNull(id.legal_name, id.legalName, payload && payload.meta && payload.meta.legal_name),
76	    company_number: firstNonNull(id.company_number, id.companyNumber, payload && payload.meta && payload.meta.company_number),
77	  };
78	}
79	
80	function extractSector(payload) {
81	  return {
82	    sector: firstNonNull(
83	      payload && payload.meta && payload.meta.sector,
84	      payload && payload.sector,
85	      payload && payload.identity && payload.identity.sector
86	    ),
87	    sub_sector: firstNonNull(
88	      payload && payload.meta && payload.meta.sub_sector,
89	      payload && payload.meta && payload.meta.subSector,
90	      payload && payload.sub_sector
91	    ),
92	  };
93	}
94	
95	function asArray(v) {
96	  if (v == null) return [];
97	  return Array.isArray(v) ? v : [v];
98	}
99	
100	// say(list, check, detail): the one shared shape every per-expectation-kind verifier below pushes
101	// onto its contradictions/abstentions/matches list. Pulled to module scope (it captures nothing
102	// from any enclosing closure) so each verifier below does not redeclare it.
103	function say(list, check, detail) {
104	  list.push({ check, detail });
105	}
106	
107	function extractBound(payload) {
108	  const j = (payload && (payload.jurisdiction || payload.markets)) || {};
109	  let bound = asArray(firstNonNull(j.bound, payload && payload.jurisdictions_bound));
110	  if (bound.length === 0) {
111	    // Legacy shape: meta.country is the single asserted binding country.
112	    const c = payload && payload.meta && payload.meta.country;
113	    if (c) bound = [c];
114	  }
115	  return bound.map(toJurisdictionCode).filter(Boolean);
116	}
117	
118	// A finding is "asserted" unless it carries an explicit non-assertive state.
119	const NON_ASSERT_STATES = new Set([
120	  'pass', 'ok', 'compliant', 'needs-review', 'needs_review', 'review',
121	  'unverified', 'info', 'informational', 'observation', 'not_applicable', 'na', 'abstain',
122	]);
123	
124	function findingIsAsserted(f) {
125	  const state = norm(firstNonNull(f && f.state, f && f.status, f && f.verdict));
126	  if (!state) return true;
127	  return !NON_ASSERT_STATES.has(state.replace(/ /g, '_')) && !NON_ASSERT_STATES.has(state);
128	}
129	
130	function findingText(f, frameworkName) {
131	  const parts = [frameworkName || ''];
132	  (function walk(v, depth) {
133	    if (depth > 3 || v == null) return;
134	    if (typeof v === 'string') { parts.push(v); return; }
135	    if (Array.isArray(v)) { v.forEach((x) => walk(x, depth + 1)); return; }
136	    if (typeof v === 'object') { Object.keys(v).forEach((k) => walk(v[k], depth + 1)); }
137	  })(f, 0);
138	  return parts.join(' \n ');
139	}
140	
141	// frameworkDisplayName(fw) -> the best-effort display name for one payload.frameworks[] entry.
142	function frameworkDisplayName(fw) {
143	  return firstNonNull(fw && fw.name, fw && fw.framework, fw && fw.title, fw && fw.law, '');
144	}
145	
146	// collectFrameworkFindings(fw, name) -> [{text, framework}] for one framework entry's own
147	// findings/items list, asserted findings only.
148	function collectFrameworkFindings(fw, name) {
149	  const out = [];
150	  const findings = asArray(fw && (fw.findings || fw.items));
151	  for (const f of findings) {
152	    if (!findingIsAsserted(f)) continue;
153	    out.push({ text: findingText(f, name), framework: String(name) });
154	  }
155	  return out;
156	}
157	
158	// collectFlatFindings(payload) -> [{text, framework}] for the payload's own flat findings[] list
159	// (if it carries one), asserted findings only.
160	function collectFlatFindings(payload) {
161	  const out = [];
162	  for (const f of asArray(payload && payload.findings)) {
163	    if (!findingIsAsserted(f)) continue;
164	    const framework = firstNonNull(f && f.framework, '');
165	    out.push({ text: findingText(f, framework), framework: String(framework) });
166	  }
167	  return out;
168	}
169	
170	// Returns { frameworkNames: string[], assertedFindings: [{text, framework}] }
171	function extractFindings(payload) {
172	  const frameworkNames = [];
173	  const assertedFindings = [];
174	  for (const fw of asArray(payload && payload.frameworks)) {
175	    const name = frameworkDisplayName(fw);
176	    if (name) frameworkNames.push(String(name));
177	    assertedFindings.push(...collectFrameworkFindings(fw, name));
178	  }
179	  // Flat findings list, if the payload carries one.
180	  assertedFindings.push(...collectFlatFindings(payload));
181	  return { frameworkNames, assertedFindings };
182	}
183	
184	// ---------- the verifier ----------
185	
186	function loadReferenceSet(setPath) {
187	  const p = setPath || DEFAULT_SET;
188	  return JSON.parse(fs.readFileSync(p, 'utf8'));
189	}
190	
191	function findFirm(refSet, domain) {
192	  const nd = norm(domain).replace(/ /g, '');
193	  return (refSet.firms || []).find((f) => norm(f.domain).replace(/ /g, '') === nd) || null;
194	}
195	
196	// Every per-expectation-kind verifier below has the exact same shape: (payload/exp/whatever it
197	// needs) -> { contradictions[], abstentions[], matches[] }. verifyPayload (the aggregator, at the
198	// foot of this section) just concatenates them. This is the decomposition of the former single
199	// 121-line/43-branch verifyPayload (Constitution Rule 4/tools/health-gate/check.js caps): each
200	// expectation kind below is independently readable, and none of the underlying match/abstain/
201	// contradict LOGIC changed - only where the code lives.
202	
203	// 1. legal name, 2. company number (compared with whitespace stripped, case-insensitive)
204	function verifyIdentity(payload, exp) {
205	  const contradictions = [];
206	  const abstentions = [];
207	  const matches = [];
208	
209	  const identity = extractIdentity(payload);
210	  if (exp.legal_name != null) {
211	    if (identity.legal_name == null) {
212	      say(abstentions, 'legal_name', `expected "${exp.legal_name}", engine abstained`);
213	    } else if (norm(identity.legal_name) === norm(exp.legal_name)) {
214	      say(matches, 'legal_name', identity.legal_name);
215	    } else {
216	      say(contradictions, 'legal_name', `expected "${exp.legal_name}", engine asserted "${identity.legal_name}"`);
217	    }
218	  }
219	
220	  if (exp.company_number != null) {
221	    const got = identity.company_number;
222	    const strip = (v) => String(v).replace(/\s+/g, '').toUpperCase();
223	    if (got == null) {
224	      say(abstentions, 'company_number', `expected ${exp.company_number}, engine abstained`);
225	    } else if (strip(got) === strip(exp.company_number)) {
226	      say(matches, 'company_number', got);
227	    } else {
228	      say(contradictions, 'company_number', `expected ${exp.company_number}, engine asserted ${got}`);
229	    }
230	  }
231	
232	  return { contradictions, abstentions, matches };
233	}
234	
235	// 3. sector / sub_sector (loose token match; a different asserted sector contradicts)
236	function verifySector(payload, exp) {
237	  const contradictions = [];
238	  const abstentions = [];
239	  const matches = [];
240	
241	  const sec = extractSector(payload);
242	  if (exp.sector != null) {
243	    const asserted = firstNonNull(sec.sector, sec.sub_sector);
244	    if (asserted == null) {
245	      say(abstentions, 'sector', `expected "${exp.sector}", engine abstained`);
246	    } else if (looseMatch(asserted, exp.sector) || (exp.sub_sector && looseMatch(asserted, exp.sub_sector))) {
247	      say(matches, 'sector', asserted);
248	    } else {
249	      say(contradictions, 'sector', `expected "${exp.sector}"${exp.sub_sector ? ` / "${exp.sub_sector}"` : ''}, engine asserted "${asserted}"`);
250	    }
251	  }
252	  if (exp.sub_sector != null && sec.sub_sector != null) {
253	    if (looseMatch(sec.sub_sector, exp.sub_sector) || looseMatch(sec.sub_sector, exp.sector)) {
254	      say(matches, 'sub_sector', sec.sub_sector);
255	    } else {
256	      say(contradictions, 'sub_sector', `expected "${exp.sub_sector}", engine asserted "${sec.sub_sector}"`);
257	    }
258	  }
259	
260	  return { contradictions, abstentions, matches };
261	}
262	
263	// 4. jurisdictions_bound: asserting a BINDING jurisdiction outside the verified bound list is a
264	//    contradiction. jurisdictions_serves is marketing reach (Constitution Rule 13: serving a market
265	//    is not being bound by its law) and MUST NOT widen the allowed-binding set - an engine that
266	//    binds a jurisdiction the reference set records only as served is emitting a false nexus.
267	function verifyJurisdictions(payload, exp) {
268	  const contradictions = [];
269	  const abstentions = [];
270	  const matches = [];
271	
272	  if (!Array.isArray(exp.jurisdictions_bound)) return { contradictions, abstentions, matches };
273	
274	  const allowed = new Set(exp.jurisdictions_bound.map(toJurisdictionCode));
275	  const got = extractBound(payload);
276	  if (got.length === 0) {
277	    say(abstentions, 'jurisdictions_bound', `expected [${exp.jurisdictions_bound.join(', ')}], engine abstained`);
278	    return { contradictions, abstentions, matches };
279	  }
280	
281	  for (const code of got) {
282	    if (allowed.has(code)) say(matches, 'jurisdictions_bound', code);
283	    else say(contradictions, 'jurisdictions_bound', `engine asserted binding jurisdiction "${code}" which is not in the verified list [${[...allowed].join(', ')}]`);
284	  }
285	  for (const code of exp.jurisdictions_bound.map(toJurisdictionCode)) {
286	    if (!got.includes(code)) say(abstentions, 'jurisdictions_bound', `verified bound jurisdiction "${code}" not asserted by the engine`);
287	  }
288	
289	  return { contradictions, abstentions, matches };
290	}
291	
292	// 5. expected_frameworks_min: missing = abstention (allowed, logged)
293	function verifyFrameworks(exp, frameworkNames, corpus) {
294	  const contradictions = [];
295	  const abstentions = [];
296	  const matches = [];
297	
298	  if (!Array.isArray(exp.expected_frameworks_min)) return { contradictions, abstentions, matches };
299	
300	  for (const fw of exp.expected_frameworks_min) {
301	    const hit = frameworkNames.some((n) => looseMatch(n, fw)) || norm(corpus).includes(norm(fw));
302	    if (hit) say(matches, 'expected_framework', fw);
303	    else say(abstentions, 'expected_framework', `verified binding framework not attached: "${fw}"`);
304	  }
305	
306	  return { contradictions, abstentions, matches };
307	}
308	
309	// 6. known_breaches: found = match, not found = abstention
310	function verifyKnownBreaches(exp, assertedFindings) {
311	  const contradictions = [];
312	  const abstentions = [];
313	  const matches = [];
314	
315	  if (!Array.isArray(exp.known_breaches)) return { contradictions, abstentions, matches };
316	
317	  for (const kb of exp.known_breaches) {
318	    const terms = asArray(kb.match_any);
319	    const hit = assertedFindings.some((f) => terms.some((t) => norm(f.text).includes(norm(t))));
320	    const label = kb.id || kb.framework;
321	    if (hit) say(matches, 'known_breach', label);
322	    else say(abstentions, 'known_breach', `verified real problem not found: ${label} (${kb.description || ''})`);
323	  }
324	
325	  return { contradictions, abstentions, matches };
326	}
327	
328	// 7. known_non_breaches: ANY asserted finding matching one is a contradiction.
329	function verifyKnownNonBreaches(exp, assertedFindings) {
330	  const contradictions = [];
331	  const abstentions = [];
332	  const matches = [];
333	
334	  if (!Array.isArray(exp.known_non_breaches)) return { contradictions, abstentions, matches };
335	
336	  for (const knb of exp.known_non_breaches) {
337	    const terms = asArray(knb.match_any);
338	    const hits = assertedFindings.filter((f) => terms.some((t) => norm(f.text).includes(norm(t))));
339	    const label = knb.id || knb.framework;
340	    if (hits.length > 0) {
341	      say(contradictions, 'known_non_breach', `${label}: engine asserted a hand-verified non-breach (${hits.length} finding(s), first in framework "${hits[0].framework}"). ${knb.description || ''}`);
342	    } else {
343	      say(matches, 'known_non_breach', `${label} correctly not asserted`);
344	    }
345	  }
346	
347	  return { contradictions, abstentions, matches };
348	}
349	
350	// verifyBreaches: the small aggregator over 6+7 (both read the same assertedFindings list, so
351	// they are one "kind" of expectation - known-vs-asserted breach matching - split in two only
352	// because "found" and "must never be found" are different polarities worth reading separately).
353	function verifyBreaches(exp, assertedFindings) {
354	  const kb = verifyKnownBreaches(exp, assertedFindings);
355	  const knb = verifyKnownNonBreaches(exp, assertedFindings);
356	  return {
357	    contradictions: kb.contradictions.concat(knb.contradictions),
358	    abstentions: kb.abstentions.concat(knb.abstentions),
359	    matches: kb.matches.concat(knb.matches),
360	  };
361	}
362	
363	/**
364	 * verifyPayload(payload, firm) -> { domain, contradictions[], abstentions[], matches[] }
365	 * Pure function; no I/O. Any entry in contradictions means the engine CONTRADICTED
366	 * a hand-verified expectation and the harness must fail. A small aggregator over the
367	 * per-expectation-kind verifiers above - it invents no matching/abstaining/contradicting logic
368	 * of its own.
369	 */
370	function verifyPayload(payload, firm) {
