372	  const { frameworkNames, assertedFindings } = extractFindings(payload);
373	  const corpus = frameworkNames.join(' \n ');
374	
375	  const parts = [
376	    verifyIdentity(payload, exp),
377	    verifySector(payload, exp),
378	    verifyJurisdictions(payload, exp),
379	    verifyFrameworks(exp, frameworkNames, corpus),
380	    verifyBreaches(exp, assertedFindings),
381	  ];
