383	  const contradictions = parts.flatMap((p) => p.contradictions);
384	  const abstentions = parts.flatMap((p) => p.abstentions);
385	  const matches = parts.flatMap((p) => p.matches);
386	
387	  return {
388	    domain: firm ? firm.domain : extractDomain(payload),
389	    role: firm ? firm.role : null,
390	    contradictions,
391	    abstentions,
392	    matches,
393	    ok: contradictions.length === 0,
394	  };
