399	// parseCliArgs(argv) -> {opts} on success, or {exitCode} when parsing itself must abort (an
400	// unrecognised flag, or no payload path given at all). Mirrors the original inline loop exactly:
401	// an unknown argument prints its own message and aborts immediately, before the payload-path
402	// check below ever runs.
403	function parseCliArgs(argv) {
404	  const args = argv.slice(2);
405	  const opts = { json: false, set: DEFAULT_SET, domain: null, payloadPath: null };
406	  for (let i = 0; i < args.length; i++) {
407	    const a = args[i];
408	    if (a === '--json') opts.json = true;
409	    else if (a === '--set') opts.set = args[++i];
410	    else if (a === '--domain') opts.domain = args[++i];
411	    else if (!opts.payloadPath) opts.payloadPath = a;
412	    else { console.error(`Unknown argument: ${a}`); return { exitCode: 2 }; }
413	  }
414	  if (!opts.payloadPath) {
415	    console.error('Usage: node eval/reference-set/verify.js <payload.json> [--set <reference-set.json>] [--domain <domain>] [--json]');
416	    return { exitCode: 2 };
417	  }
418	  return { opts };
419	}
420	
421	// loadPayloadAndRefSet(opts) -> {payload, refSet} on success, or {exitCode} on any read/parse
422	// failure of either file.
423	function loadPayloadAndRefSet(opts) {
424	  let payload;
425	  try {
426	    payload = JSON.parse(fs.readFileSync(opts.payloadPath, 'utf8'));
427	  } catch (e) {
428	    console.error(`Cannot read payload ${opts.payloadPath}: ${e.message}`);
429	    return { exitCode: 2 };
430	  }
431	  let refSet;
432	  try {
433	    refSet = loadReferenceSet(opts.set);
434	  } catch (e) {
435	    console.error(`Cannot read reference set ${opts.set}: ${e.message}`);
436	    return { exitCode: 2 };
437	  }
438	  return { payload, refSet };
439	}
440	
441	// resolveFirm(opts, payload, refSet) -> {firm} on success, or {exitCode} when the payload carries
442	// no domain, or the domain is not in the reference set at all.
443	function resolveFirm(opts, payload, refSet) {
444	  const domain = opts.domain || extractDomain(payload);
445	  if (!domain) {
446	    console.error('Payload carries no meta.domain and no --domain was given.');
447	    return { exitCode: 2 };
448	  }
449	  const firm = findFirm(refSet, domain);
450	  if (!firm) {
451	    console.error(`Domain "${domain}" is not in the reference set (${refSet.firms.length} firms). Nothing to verify.`);
452	    return { exitCode: 2 };
453	  }
454	  return { firm };
455	}
456	
457	// printReport(report, json) -> the CLI's human/--json output, unchanged from the original inline
458	// block in main().
459	function printReport(report, json) {
460	  if (json) {
461	    console.log(JSON.stringify(report, null, 2));
462	    return;
463	  }
464	  console.log(`reference-set verify: ${report.domain} (${report.role})`);
465	  console.log(`  matches:        ${report.matches.length}`);
466	  for (const m of report.matches) console.log(`    MATCH   [${m.check}] ${m.detail}`);
467	  console.log(`  abstentions:    ${report.abstentions.length} (allowed)`);
468	  for (const a of report.abstentions) console.log(`    ABSTAIN [${a.check}] ${a.detail}`);
469	  console.log(`  contradictions: ${report.contradictions.length}`);
470	  for (const c of report.contradictions) console.log(`    FAIL    [${c.check}] ${c.detail}`);
471	  console.log(report.ok ? 'RESULT: OK (no contradictions)' : 'RESULT: CONTRADICTION - the engine contradicted hand-verified ground truth');
472	}
473	
474	function main(argv) {
475	  const parsed = parseCliArgs(argv);
476	  if (parsed.exitCode) return parsed.exitCode;
477	  const { opts } = parsed;
478	
479	  const loaded = loadPayloadAndRefSet(opts);
480	  if (loaded.exitCode) return loaded.exitCode;
481	  const { payload, refSet } = loaded;
482	
483	  const resolved = resolveFirm(opts, payload, refSet);
484	  if (resolved.exitCode) return resolved.exitCode;
485	  const { firm } = resolved;
486	
487	  const report = verifyPayload(payload, firm);
488	  printReport(report, opts.json);
489	  return report.ok ? 0 : 1;
490	}
491	
492	if (require.main === module) {
493	  process.exit(main(process.argv));
494	}
