274	function statusOf(report, check) {
275	  if (!report) return '-';
276	  if (report.contradictions.some((c) => c.check === check)) return 'CONTRADICT';
277	  if (report.matches.some((m) => m.check === check)) return 'match';
278	  if (report.abstentions.some((a) => a.check === check)) return 'abstain';
279	  return '-';
280	}
