287	// printPlaceholderRow(r, W, status) -> the placeholder row for UNREACHABLE/ERROR/MISSING statuses
288	// (the status label that varies between the original two inline blocks is now a parameter).
289	function printPlaceholderRow(r, W, status) {
290	  console.log([pad(r.domain, W[0]), pad(r.role, W[1]), pad('-', W[2]), pad('-', W[3]), pad('-', W[4]), pad('-', W[5]), pad(status, W[6])].join(' '));
291	}
