304	// printFirmRow(r, W) -> the full data row for a firm that actually ran (not UNREACHABLE/ERROR/MISSING).
305	function printFirmRow(r, W) {
306	  const sec = statusOf(r.report, 'sector');
307	  const jur = statusOf(r.report, 'jurisdictions_bound');
308	  const capCell = r.caps ? (r.caps.present + '/' + r.caps.total) : 'n/a';
309	  const resultCell = r.status === 'OK' && r.bundle_unreachable ? 'OK*' : r.status;
310	  console.log([
311	    pad(r.domain, W[0]),
312	    pad(r.role, W[1]),
313	    pad(sectorCellText(sec), W[2]),
314	    pad(r.sub_sector_note || '-', W[3]),
315	    pad(formatJurCell(jur, r.bound), W[4]),
316	    pad(capCell, W[5]),
317	    pad(resultCell, W[6]),
318	  ].join(' '));
319	}
