86	function fetchOnce(url) {
87	  return new Promise((resolve, reject) => {
88	    // Single door: every hop (initial attempt AND every redirect, since redirects re-enter here)
89	    // is re-parsed and re-validated for host safety before a socket is opened. A hostname-shaped
90	    // string is never trusted; localhost/loopback/private/link-local targets are refused (CR#21).
91	    const u = parseSafeFetchTarget(url);
92	    if (!u) return reject(new Error(`refused unsafe or malformed fetch target: ${url}`));
93	    const lib = u.protocol === 'http:' ? http : https;
94	    const req = lib.request(
95	      u,
96	      {
97	        method: 'GET',
98	        headers: {
99	          'User-Agent': USER_AGENT,
100	          Accept: 'text/html,application/xhtml+xml;q=0.9,*/*;q=0.5',
101	          'Accept-Language': 'en-GB,en;q=0.9',
102	          'Accept-Encoding': 'gzip, deflate',
103	        },
104	        timeout: FETCH_DEADLINE_MS,
105	        // Pin the connection to a resolved address that has passed the private/loopback/link-local
106	        // blocklist. Without this, parseSafeFetchTarget validates only the HOSTNAME and DNS could
107	        // still resolve it to an internal address after the check (DNS-rebinding SSRF).
108	        lookup: safeLookup,
109	      },
110	      (res) => {
111	        const chunks = [];
112	        let bytes = 0;
113	        let stream = res;
114	        const enc = String(res.headers['content-encoding'] || '').toLowerCase();
115	        if (enc.includes('gzip')) stream = res.pipe(zlib.createGunzip());
116	        else if (enc.includes('deflate')) stream = res.pipe(zlib.createInflate());
117	        else if (enc.includes('br')) stream = res.pipe(zlib.createBrotliDecompress());
