124	          }
125	          chunks.push(c);
126	        });
127	        stream.on('end', () => resolve({ status: res.statusCode, headers: res.headers, body: Buffer.concat(chunks).toString('utf8') }));
128	        stream.on('error', (e) => reject(e));
129	      }
130	    );
131	    req.on('timeout', () => { req.destroy(new Error(`timeout after ${FETCH_DEADLINE_MS}ms`)); });
132	    req.on('error', (e) => reject(e));
133	    req.end();
134	  });
