141	      setTimeout(() => rej(new Error(`hard deadline ${FETCH_DEADLINE_MS}ms exceeded`)), FETCH_DEADLINE_MS + 500).unref()
142	    );
143	    const res = await Promise.race([fetchOnce(current), outerDeadline]);
144	    if ([301, 302, 303, 307, 308].includes(res.status) && res.headers.location) {
145	      current = new URL(res.headers.location, current).href;
146	      continue;
147	    }
148	    return { finalUrl: current, status: res.status, body: res.body };
149	  }
