'use strict';
// Verify the LIVE-gate red-team fixtures against the real modules (Rule 17: ground truth).
const path = require('path');
const ROOT = '/Users/amanigga/Desktop/TAMAZIA-REBUILD/tamazia-audit-engine';
const fx = require(path.join(ROOT, 'eval/red-team/fixtures.json'));
const identity = require(path.join(ROOT, 'facts/identity.js'));
const sector = require(path.join(ROOT, 'facts/sector.js'));
const jurisdiction = require(path.join(ROOT, 'facts/jurisdiction.js'));
const oracle = require(path.join(ROOT, 'evidence/browser/oracle.js'));
const { observe } = require(path.join(ROOT, 'evidence/browser/observe.js'));
const bfl = require(path.join(ROOT, 'eval/reference-set/build-fixtures-lib.js'));

const get = (id) => fx.fixtures.find((f) => f.id === id);
let fails = 0;
const ok = (c, m) => { console.log((c ? 'PASS ' : 'FAIL ') + m); if (!c) fails++; };

// ---- RT-D bot wall ----
const d = get('RT-D-BOT-WALL');
ok(bfl.looksLikeChallengePage(d.input.fetch.status, d.input.fetch.body_text, d.input.fetch.title) === true,
  'RT-D: looksLikeChallengePage(403, cloudflare) === true');
const dn = d.input.naive_bundle;
const dSector = sector.resolveSector(dn);
const dJur = jurisdiction.resolveJurisdiction(dn);
const dId = identity.resolveIdentity(dn);
ok(!dSector.value, 'RT-D: sector abstains on challenge-text bundle (value=' + JSON.stringify(dSector.value) + ')');
ok(dJur.abstained === true || dJur.bound.length === 0, 'RT-D: jurisdiction abstains (bound=' + JSON.stringify(dJur.bound.map(b=>b.jurisdiction)) + ')');
ok(!dId.legal_name.value || dId.legal_name.confidence === 'weak', 'RT-D: identity legal_name not confident (val=' + JSON.stringify(dId.legal_name.value) + ', conf=' + dId.legal_name.confidence + ')');

// ---- RT-E foreign language (live partial: sector abstains) ----
const e = get('RT-E-FOREIGN-LANGUAGE');
const eSector = sector.resolveSector(e.input.bundle);
ok(!eSector.value, 'RT-E: sector abstains on French corpus (value=' + JSON.stringify(eSector.value) + ')');
const eJur = jurisdiction.resolveJurisdiction(e.input.bundle);
console.log('     RT-E info: jurisdiction bound=' + JSON.stringify(eJur.bound.map(b=>b.jurisdiction)) + ' serves=' + JSON.stringify((eJur.serves||[]).map(s=>s.jurisdiction||s)) + ' subs=' + JSON.stringify(eJur.sub_jurisdictions));

// ---- RT-F contradictory entity ----
const f = get('RT-F-CONTRADICTORY-ENTITY');
const fId = identity.resolveIdentity(f.input.bundle);
ok(fId.legal_name.confidence !== 'register' && fId.legal_name.confidence !== 'corroborated',
  'RT-F: legal_name not asserted at register/corroborated (val=' + JSON.stringify(fId.legal_name.value) + ', conf=' + fId.legal_name.confidence + ')');
ok(fId.company_number.value == null,
  'RT-F: company_number abstains on the conflict (val=' + JSON.stringify(fId.company_number.value) + ', conf=' + fId.company_number.confidence + ')');
console.log('     RT-F info notes: ' + JSON.stringify(fId.notes));

// ---- RT-G essential cookie ----
const g = get('RT-G-ESSENTIAL-COOKIE-PRECONSENT');
for (const c of g.input.cookies_pre_consent) {
  const v = oracle.classifyCookie(c).verdict;
  ok(v === 'essential', 'RT-G: classifyCookie(' + c.name + ').verdict === essential (got ' + v + ')');
}
// lane-level via scripted fake browser
function fakeBrowserFrom(script) {
  return async function launchBrowser() {
    let phase = 'pre';
    const handlers = [];
    return {
      async newPage() {
        return {
          on(evt, h) { if (evt === 'request') handlers.push(h); },
          async goto() {},
          async settle() {},
          async cookies() { return (phase === 'pre' ? script.pre_consent.cookies : script.post_consent.cookies); },
          async findConsentControl() { return script.consent_control; },
          async clickConsent() { phase = 'post'; },
        };
      },
      async close() {},
    };
  };
}
(async () => {
  const res = await observe(g.input.browser_script.url, {
    launchBrowser: fakeBrowserFrom(g.input.browser_script),
    now: () => 1_700_000_000_000,
    fetchLink: async () => ({ ok: true, status: 200 }),
  });
  ok(res.lane.ran === true, 'RT-G: observe lane.ran === true (reason=' + JSON.stringify(res.lane.reason) + ')');
  ok(res.observed.length === 0, 'RT-G: observed is empty for essential-only pre-consent (got ' + JSON.stringify(res.observed.map(o=>o.name)) + ')');

  console.log('\n' + (fails === 0 ? 'ALL LIVE RED-TEAM PASS CONDITIONS HOLD' : fails + ' FAILURE(S)'));
  process.exit(fails === 0 ? 0 : 1);
})();

